mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A2.SBSCRB_DE DESC) AS RNUM , COALESCE( A2.ESNTL_ID , '' ) AS ESNTL_ID , COALESCE( A2.USER_ID , '' ) AS USER_ID , COALESCE( A2.USER_NM , '' ) AS USER_NM , COALESCE( A2.EMAIL_ADRES , '' ) AS EMAIL_ADRES , COALESCE( A2.USR_TELNO , '' ) AS USR_TELNO , COALESCE( A2.MBTLNUM , '' ) AS mbtlnum , COALESCE( A2.MBER_STTUS , '' ) AS MBER_STTUS , CASE A2.MBER_STTUS WHEN 'A' THEN '대기' WHEN 'P' THEN '사용' WHEN 'D' THEN '탈퇴' ELSE A2.MBER_STTUS END AS MBER_STTUS_NM , COALESCE(DATE_FORMAT(A2.SBSCRB_DE, '%Y-%m-%d') , '' ) AS SBSCRB_DE , COALESCE(DATE_FORMAT(A2.SECSN_DE, '%Y-%m-%d') , '' ) AS SECSN_DE , COALESCE( IF(LOCK_AT='Y', '잠금', '해제') , '해제') AS LOCK_AT , A2.USER_SE FROM ARMUSER A2 WHERE 1=1 AND A2.USER_SE = 'GNR'
AND A2.USER_NM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBTLNUM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBER_STTUS = #{joGunMberSta}
) A1 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT COUNT(1) FROM ( SELECT A2.ESNTL_ID FROM ARMUSER A2 WHERE 1=1 AND A2.USER_SE = 'GNR'
AND A2.USER_NM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBTLNUM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBER_STTUS = #{joGunMberSta}
) A1

SELECT IF( COUNT(1), 'N', 'Y' ) AS checkYn
  FROM ARMUSER
 WHERE USER_ID = #{userId}

SELECT IF( COUNT(1), 'N', 'Y' ) AS checkYn
  FROM ARMUSER
 WHERE USER_ID = #{userId}
   AND ESNTL_ID != #{esntlId}

